{
  "title": "Intermediate Python Mastery",
  "description": "This course is designed for intermediate learners who want to deepen their understanding of Python and explore advanced topics that can enhance their programming skills.",
  "modules": [
    {
      "id": "module_1",
      "title": "Advanced Python Concepts",
      "description": "Dive into advanced topics such as decorators, generators, context managers, and metaclasses to write more efficient and Pythonic code."
    },
    {
      "id": "module_2",
      "title": "Data Manipulation and Analysis",
      "description": "Explore libraries such as Pandas and NumPy for data manipulation, analysis, and visualization to handle complex datasets effectively."
    },
    {
      "id": "module_3",
      "title": "Web Development with Flask",
      "description": "Learn to build web applications using Flask, covering routing, templates, and database integration to create dynamic web solutions."
    },
    {
      "id": "module_4",
      "title": "Automation and Scripting",
      "description": "Understand how to automate tasks using Python scripts, including file handling, web scraping, and interacting with APIs to improve productivity."
    }
  ]
}
